def encode_list(lst):
    runs = []
    if not lst:
        return runs
    current_value = lst[0]
    count = 1
    for i in range(1, len(lst)):
        if lst[i] == current_value:
            count += 1
        else:
            runs.append([count, current_value])
            current_value = lst[i]
            count = 1
    runs.append([count, current_value])
    return runs
